// Extraction du body (n8n place le body dans json.body en mode Webhook)
const body = $input.first().json.body ?? $input.first().json;

// Nettoyage des chaînes
const contact_name      = String(body.contact_name      ?? '').trim();
const contact_phone     = String(body.contact_phone     ?? '').trim();
const contact_email     = String(body.contact_email     ?? '').trim();
const device_type       = String(body.device_type       ?? '').trim();
const device_brand      = String(body.device_brand      ?? '').trim();
const device_model      = String(body.device_model      ?? '').trim();
const issue_description = String(body.issue_description ?? '').trim();
const price_estimate    = body.price_estimate !== undefined ? Number(body.price_estimate) : null;

const DEVICE_TYPES = ['smartphone', 'tablet', 'laptop', 'console', 'tv', 'appliance', 'other'];

// Validation des champs obligatoires
if (!contact_name) {
  return [{ json: { isValid: false, errorMessage: 'contact_name est requis et ne peut pas être vide.' } }];
}
if (!contact_phone) {
  return [{ json: { isValid: false, errorMessage: 'contact_phone est requis et ne peut pas être vide.' } }];
}
if (!device_type || !DEVICE_TYPES.includes(device_type)) {
  return [{ json: { isValid: false, errorMessage: 'device_type est invalide. Valeurs acceptées : ' + DEVICE_TYPES.join(', ') } }];
}
if (!issue_description || issue_description.length < 10) {
  return [{ json: { isValid: false, errorMessage: 'issue_description est requis et doit contenir au moins 10 caractères.' } }];
}
if (price_estimate !== null && isNaN(price_estimate)) {
  return [{ json: { isValid: false, errorMessage: 'price_estimate doit être un nombre valide.' } }];
}

// Données nettoyées et validées
return [{
  json: {
    isValid: true,
    contact_name,
    contact_phone,
    contact_email: contact_email || null,
    device_type,
    device_brand:       device_brand       || null,
    device_model:       device_model       || null,
    issue_description,
    price_estimate:     price_estimate !== null && !isNaN(price_estimate) ? price_estimate : null
  }
}];

// Supabase retourne un tableau avec Prefer: return=representation
const ticketArray = $input.first().json;
const ticket = Array.isArray(ticketArray) ? ticketArray[0] : ticketArray;

if (!ticket || !ticket.tracking_token) {
  throw new Error('TICKET_CREATION_ERROR: tracking_token absent de la réponse Supabase.');
}

// upsert_contact retourne directement l'UUID (scalaire JSON)
const contactIdRaw = $('Upsert Contact').first().json;
const contactId = typeof contactIdRaw === 'string' ? contactIdRaw : String(contactIdRaw);

const validatedData = $('Validate Input').first().json;
const trackingUrl = `${$env.APP_URL}/track/${ticket.tracking_token}`;

return [{
  json: {
    ticket_id:      ticket.id,
    tracking_token: ticket.tracking_token,
    tracking_url:   trackingUrl,
    contact_id:     contactId,
    contact_name:   validatedData.contact_name,
    contact_phone:  validatedData.contact_phone,
    contact_email:  validatedData.contact_email,
    device_brand:   validatedData.device_brand  ?? '',
    device_model:   validatedData.device_model  ?? ''
  }
}];

// Récupère les données préparées par Build Tracking URL
const data = $('Build Tracking URL').first().json;

// L'email a été envoyé si contact_email était renseigné (le Switch l'a routé vers Send Welcome Email)
const notifications_sent = ['sms'];
if (data.contact_email) {
  notifications_sent.push('email');
}

return [{
  json: {
    success:        true,
    ticket_id:      data.ticket_id,
    tracking_token: data.tracking_token,
    tracking_url:   data.tracking_url,
    contact_id:     data.contact_id,
    notifications_sent
  }
}];
